async function seed() {
  await client.connect();
  console.log('Connected to Neon database');

  // Drop and recreate tables
  await client.query('DROP TABLE IF EXISTS prices CASCADE');
  await client.query('DROP TABLE IF EXISTS products CASCADE');
  await client.query('DROP TABLE IF EXISTS supermarkets CASCADE');
  console.log('Dropped existing tables');

  await client.query(`
    CREATE TABLE supermarkets (
      id SERIAL PRIMARY KEY,
      name VARCHAR(100) NOT NULL,
      slug VARCHAR(50) NOT NULL UNIQUE,
      logo_url VARCHAR(500),
      website_url VARCHAR(500) NOT NULL
    )
  `);

  await client.query(`
    CREATE TABLE products (
      id SERIAL PRIMARY KEY,
      name VARCHAR(300) NOT NULL,
      brand VARCHAR(100) NOT NULL,
      category VARCHAR(100) NOT NULL,
      unit VARCHAR(50) NOT NULL,
      image_url VARCHAR(500)
    )
  `);

  await client.query(`
    CREATE TABLE prices (
      id SERIAL PRIMARY KEY,
      product_id INT NOT NULL REFERENCES products(id) ON DELETE CASCADE,
      supermarket_id INT NOT NULL REFERENCES supermarkets(id) ON DELETE CASCADE,
      price INT NOT NULL,
      last_updated TIMESTAMP DEFAULT NOW(),
      UNIQUE(product_id, supermarket_id)
    )
  `);
  console.log('Created tables');

  // Seed supermarkets
  for (const sm of SUPERMARKETS) {
    await client.query(
      'INSERT INTO supermarkets (name, slug, logo_url, website_url) VALUES ($1, $2, $3, $4)',
      [sm.name, sm.slug, sm.logo_url, sm.website_url]
    );
  }
  console.log(`Seeded ${SUPERMARKETS.length} supermarkets`);

  // Get supermarket IDs
  const { rows: smRows } = await client.query('SELECT id, slug FROM supermarkets ORDER BY id');
  const smIdMap = new Map();
  for (const sm of smRows) {
    smIdMap.set(sm.slug, sm.id);
  }

  const slugOrder = ['jumbo', 'lider', 'tottus', 'unimarc', 'santa-isabel'];

  // Batch insert products (50 at a time)
  const BATCH_SIZE = 50;
  const productIds = [];
  for (let b = 0; b < PRODUCTS.length; b += BATCH_SIZE) {
    const batch = PRODUCTS.slice(b, b + BATCH_SIZE);
    const values = [];
    const params = [];
    batch.forEach(([name, brand, category, unit], i) => {
      const offset = i * 4;
      values.push(`($${offset+1}, $${offset+2}, $${offset+3}, $${offset+4})`);
      params.push(name, brand, category, unit);
    });
    const { rows } = await client.query(
      `INSERT INTO products (name, brand, category, unit) VALUES ${values.join(', ')} RETURNING id`,
      params
    );
    for (const row of rows) productIds.push(row.id);
    console.log(`  Inserted products ${b+1}-${Math.min(b+BATCH_SIZE, PRODUCTS.length)}`);
  }

  // Batch insert prices (100 at a time)
  const priceRows = [];
  for (let p = 0; p < PRODUCTS.length; p++) {
    const basePrices = PRODUCTS[p][4];
    const productId = productIds[p];
    for (let i = 0; i < slugOrder.length; i++) {
      const price = basePrices[i];
      if (price > 0) {
        const smId = smIdMap.get(slugOrder[i]);
        if (smId) priceRows.push([productId, smId, price]);
      }
    }
  }

  const PRICE_BATCH = 100;
  for (let b = 0; b < priceRows.length; b += PRICE_BATCH) {
    const batch = priceRows.slice(b, b + PRICE_BATCH);
    const values = [];
    const params = [];
    batch.forEach(([pid, sid, price], i) => {
      const offset = i * 3;
      values.push(`($${offset+1}, $${offset+2}, $${offset+3})`);
      params.push(pid, sid, price);
    });
    await client.query(
      `INSERT INTO prices (product_id, supermarket_id, price) VALUES ${values.join(', ')}`,
      params
    );
  }

  console.log(`Seeded ${productIds.length} products and ${priceRows.length} prices`);
  await client.end();
  console.log('Done!');
}

seed().catch(err => {
  console.error('Seed failed:', err);
  process.exit(1);
});
